  if(!marketClosed()){const st=sessionT();if(inDom(st)){const Xs=xA(st);ctx.strokeStyle='rgba(127,209,224,.7)';ctx.lineWidth=1.2;ctx.setLineDash([2,4]);ctx.beginPath();ctx.moveTo(Xs,f.y0);ctx.lineTo(Xs,f.y1);ctx.stroke();ctx.setLineDash([]);ctx.fillStyle='#7fd1e0';ctx.font='10px monospace';ctx.textAlign='center';ctx.fillText('session T '+st.toFixed(3),Xs,f.y1-6);}}
