  const bx=DATA.overlaps.map(k=>[Math.max(0,k/10-0.045),Math.min(1,k/10+0.045)]).sort((a,b)=>a[0]-b[0]);
  const mg=[]; bx.forEach(b=>{ if(mg.length&&b[0]<=mg[mg.length-1][1]+1e-9) mg[mg.length-1][1]=Math.max(mg[mg.length-1][1],b[1]); else mg.push([b[0],b[1]]); });
