  const zcAll=[...new Set((DATA.zc||[]).map(z=>+Math.abs(z).toFixed(4)).filter(z=>z>1e-9))].sort((a,b)=>a-b);   // breaks project into current-session time at |cw| (negation half folds in: prev .9 = current .1)
